export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i++
      continue
    }
    if (arg.includes('=')) {
      result[arg.slice(2)] = arg.slice(arg.indexOf('=') + 1)
      i++
    } else {
      const key = arg.slice(2)
      result[key] = true
      // Check if next arg is a value (not a flag and not a positional)
      if (i + 1 < argv.length && argv[i + 1] !== undefined) {
        const nextArg = argv[i + 1]
        if (!nextArg.startsWith('--')) {
          result[key] = nextArg
          i += 1
        }
      }
    }
    i++
  }
  return result
}

