  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (arg.startsWith('--') && !arg.includes('=')) {
      // Check for --key=value or --key value
      const key = arg.slice(2)
      if (i + 1 < argv.length) {
        const nextArg = argv[i + 1]
