          result[key] = nextArg
          i += 2
          continue
        }
      }
      result[key] = true
      i++
    } else if (arg.includes('=')) {
      // Handle --key=value
      const eqIndex = arg.indexOf('=')
      const key = arg.slice(2, eqIndex)
      result[key] = arg.slice(eqIndex + 1)
      i++
    } else {
      // Positional argument
      result._.push(arg)
      i++
    }
  }
  return result
}

